// casegen.js — the CASE kernel: procedurally generated murder mysteries read off the goss
// civic web, with a solvability oracle and a CHAIN (each closed case scars the web).
//
// The thesis: classic Clue is famously motiveless (person + room + weapon, no why). The goss
// web inverts that — motive is the native resource. Every drama already carries its evidence,
// so a case is generated by picking a victim at the intersection of several dramas, promoting
// ONE grievance to the actual cause, and letting the rest stand as red herrings with genuine
// motive but innocence. Means, opportunity, alibis and witness independence all fall out of
// structure the web already carries:
//
//   MOTIVE       — grievancesAgainst: dramas involving the victim (AFFAIR, TRIANGLE, MATCH…),
//                  rivals (same job, near-identical webs), wronged partners (sparks against
//                  the couple map), household succession (who heads the house next).
//   TIME         — a deterministic day of six watches; each person's hats laid out as a
//                  schedule (home · work · third places), seeded off STABLE identity so a
//                  survivor keeps the same routine across every case of a chain.
//   OPPORTUNITY  — the crime happens at the victim's scheduled place on some watch; a
//                  suspect's alibi is their own scheduled place, corroborated only by
//                  INDEPENDENT witnesses (Granovetter: weak ties = evidentiary value; the
//                  household swearing to you is worth nothing — and reads that way).
//   MEANS        — items typed by place role (clinic sedative, chopshop spanner…); access is
//                  a hat query. The planted item is chosen from the culprit's access set to
//                  keep the MOST suspects alive (pacing is a generation constraint).
//   SOLVABILITY  — the oracle: the planted clue list is run through a deductive closure
//                  (eliminations only) and must converge on exactly the culprit. Sighting
//                  descriptors and a trace discriminator are added only as needed; the
//                  generator retries other watches, then other victims, before giving up.
//   THE CHAIN    — closing a case removes victim + culprit; the relational layers (ties →
//                  tribes → romance → tension → dramas) re-run over the SURVIVORS while
//                  demographics stay cast-once (nobody is renamed by a death). Case n+1 is
//                  generated from the scarred web — same seed ⇒ same casebook, forever.
//
// Pure, zero-DOM, node-tested (test/casegen.selftest.mjs). Imports the goss kernel's layers
// (the substrate is pluggable: buildGoss econ town or buildGossNave unified floor).

import { weaveTies, findTribes, findRomance, findTension, findDramas, placeName } from '../goss/gossip.js';
import { socialMetrics, scoreSociety } from '../goss/vendor/econ/econ.js';
import { mulberry32 } from '../goss/vendor/paint/voronoi.js';

// same seeded hash as gossip.js (kept local — the kernels stay independently liftable).
const hash = (...xs) => {
  let h = 1779033703 >>> 0;
  for (const x of xs) { h = Math.imul(h ^ (x >>> 0), 3432918353) >>> 0; h = ((h << 13) | (h >>> 19)) >>> 0; }
  h = Math.imul(h ^ (h >>> 16), 2246822507) >>> 0; h = Math.imul(h ^ (h >>> 13), 3266489909) >>> 0;
  return (h ^ (h >>> 16)) >>> 0;
};

export const TICKS = ['dawn', 'morning', 'midday', 'afternoon', 'evening', 'night'];
export const TICK_LABEL = ['the dawn watch', 'the morning watch', 'midday', 'the afternoon watch', 'the evening watch', 'the night watch'];
const THIRD_KINDS = ['worship', 'club', 'sport'];
const INDEP_W = 1.5;                     // ties weaker than this are "independent" (weak-tie testimony)

// ── THE DAY — each person's hats laid out over six watches, seeded off stable identity ────────
export function scheduleFor(person, seed) {
  const work = person.hats.find((h) => h.kind === 'work' && h.place !== person.home) || null;
  const thirds = person.hats.filter((h) => THIRD_KINDS.includes(h.kind));
  const r = mulberry32(hash(seed, 0x5c4d, person.orig != null ? person.orig : person.idx) || 1);
  const t1 = thirds.length ? thirds[Math.floor(r() * thirds.length)] : null;
  const t2 = thirds.length ? thirds[Math.floor(r() * thirds.length)] : null;
  const at = (h) => (h ? { place: h.place, kind: h.kind } : { place: person.home, kind: 'home' });
  return [at(null), at(work), at(t1), at(work), at(t2), at(null)];
}

// ── THE VIEW — the survivor society: demographics cast once, relations re-run ────────────────
// Removing people re-indexes densely (the goss layers expect dense arrays) but each survivor
// carries `orig` — their index in the FULL cast — so names, ages, households and routines are
// immutable facts of the town, not artifacts of who has died so far.
export function buildView(G, removed = new Set()) {
  const map = new Map();
  const people = [];
  for (const p of G.enriched.people) if (!removed.has(p.idx)) {
    map.set(p.idx, people.length);
    people.push({ ...p, idx: people.length, orig: p.orig != null ? p.orig : p.idx });
  }
  const households = [];
  for (const hh of G.enriched.households) {
    const members = hh.members.filter((i) => map.has(i)).map((i) => map.get(i));
    if (!members.length) continue;
    const head = map.has(hh.head) ? map.get(hh.head) : members[0];
    const partner = hh.partner != null && map.has(hh.partner) && map.has(hh.head) ? map.get(hh.partner) : null;   // a couple persists only whole
    households.push({ home: hh.home, surname: hh.surname, members, head, partner });
  }
  const enriched = { people, households };
  const society = { people: [], placeMembers: new Map(), affiliations: 0 };
  for (const p of G.society.people) if (map.has(p.idx)) society.people.push({ ...p, idx: map.get(p.idx) });
  for (const [pid, m] of G.society.placeMembers) {
    const mm = m.filter((i) => map.has(i)).map((i) => map.get(i));
    if (mm.length) society.placeMembers.set(pid, mm);
  }
  society.affiliations = society.people.reduce((s, p) => s + p.hats.length, 0);
  const P = society.people.length || 1;
  society.avgHats = society.affiliations / P;
  society.thirdsFrac = society.people.filter((p) => p.hats.some((h) => THIRD_KINDS.includes(h.kind))).length / P;

  const field = G.world, seed = G.seed;
  const web = weaveTies(society, enriched);
  const tribal = findTribes(field, enriched, web, seed);
  const romance = findRomance(enriched, web, tribal, seed);
  const tension = findTension(field, society, enriched, web, tribal);
  const dramas = findDramas(field, enriched, tribal, romance, tension, seed);
  const metrics = socialMetrics(field, society);
  const vital = scoreSociety(field, society, metrics);
  const placeById = new Map(field.places.map((p) => [p.id, p]));
  return { seed, field, placeById, enriched, society, web, tribal, romance, tension, dramas, vital, removedCount: removed.size };
}
const pn = (view, pid) => placeName(view.placeById.get(pid), view.seed);

// ── MOTIVE — every standing grievance against a given soul, read off the live layers ─────────
export function grievancesAgainst(view, v) {
  const M = new Map();
  const add = (i, tag, text, heat) => {
    if (i == null || i < 0 || i === v || !view.enriched.people[i]) return;
    let a = M.get(i); if (!a) M.set(i, a = []);
    a.push({ tag, text, heat: Math.round(heat) });
  };
  for (const d of view.dramas) {
    const ppl = d.people || [];
    if (!ppl.includes(v)) continue;
    for (const i of ppl) if (i !== v) add(i, d.type, d.line, d.heat);
  }
  for (const rv of view.tension.rivals) {
    const o = rv.a === v ? rv.b : rv.b === v ? rv.a : -1;
    if (o >= 0) add(o, 'RIVAL', `does the same job at the ${pn(view, rv.place)}, keeps ${Math.round(rv.overlap * 100)}% the same circles — the same regard, twice claimed.`, 40 + rv.overlap * 40);
  }
  for (const s of view.romance.sparks) {
    const o = s.a === v ? s.b : s.b === v ? s.a : -1;
    if (o < 0) continue;
    const sp = view.romance.partnerOf[o];
    if (sp >= 0) add(sp, 'WRONGED', `is bound to ${view.enriched.people[o].name} — who keeps finding the victim on the same shift, the same pew.`, 60 + s.heat * 30);
    const vp = view.romance.partnerOf[v];
    if (vp >= 0 && vp !== o) add(vp, 'WRONGED', `shares the victim's household, and has watched the victim's eye wander to ${view.enriched.people[o].name}.`, 60 + s.heat * 30);
  }
  const V = view.enriched.people[v];
  if (V.kinship === 'head') for (const hh of view.enriched.households) {
    if (hh.head !== v) continue;
    for (const m of hh.members) if (m !== v && view.enriched.people[m].age >= 18)
      add(m, 'SUCCESSION', `stands to head the ${V.surname} household the moment the victim stops breathing.`, 35);
  }
  return M;
}

// ── MEANS — items typed by place role; access is a hat query ─────────────────────────────────
const FALLBACK_MEANS = { role: null, item: 'a plain mooring cord — the kind every deck coils', tell: 'anyone with two hands and patience' };
const MEANS_ITEMS = [
  { role: 'heal', item: 'a stolen vial of clinic sedative', tell: 'someone with the run of a clinic' },
  { role: 'mend', item: 'a chopshop spanner, wiped badly', tell: 'someone with chopshop access' },
  { role: 'make', item: 'a length of works cable', tell: 'someone who walks a workshop floor' },
  { role: 'serve', item: 'a tainted canteen ration', tell: 'someone who could touch the victim’s food' },
  { role: 'grow', item: 'a garden desiccant, out of its shed', tell: 'someone with garden chemicals to hand' },
  { role: 'trade', item: 'an exchange weighing-bar', tell: 'someone at home among the market stalls' },
];
const accessRoles = (view, p) => {
  const roles = new Set();
  for (const h of p.hats) { const pl = view.placeById.get(h.place); if (pl) roles.add(pl.role === 'dwell' && h.kind === 'home garden' ? 'grow' : pl.role); }
  return roles;
};

// ── THE CASE — ground truth, the clue list, and the deductive closure that certifies it ──────
const band = (a) => (a < 30 ? 'young' : a <= 50 ? 'in their middle years' : 'grey');
const workRole = (p) => { const w = p.hats.find((h) => h.kind === 'work'); return w ? w.role : null; };

export function generateCase(view, caseSeed, n) {
  const P = view.enriched.people;
  // 1. THE VICTIM — the adult whose grievance circle is deepest and most DIVERSE (a board of
  //    red herrings needs motive types, not just bodies).
  let victim = -1, best = -1, board = null;
  for (let v = 0; v < P.length; v++) {
    if (P[v].age < 18) continue;
    const M = grievancesAgainst(view, v);
    if (M.size < 3) continue;
    const tags = new Set(); let heat = 0;
    for (const [, gs] of M) for (const g of gs) { tags.add(g.tag); heat += g.heat; }
    const score = tags.size * 12 + Math.min(M.size, 7) * 3 + heat / 100;
    if (score > best) { best = score; victim = v; board = M; }
  }
  if (victim < 0) return null;                                     // the town has gone quiet
  const V = P[victim];

  // 2. THE SUSPECTS — top 7 grievance-bearers by heat; the CULPRIT is a heat-weighted seeded draw.
  const entries = [...board.entries()]
    .map(([i, gs]) => ({ idx: i, motives: gs.sort((a, b) => b.heat - a.heat), heat: gs.reduce((s, g) => s + g.heat, 0) }))
    .sort((a, b) => b.heat - a.heat || a.idx - b.idx)
    .slice(0, 7);
  const r = mulberry32(hash(caseSeed, 0xc01d, n) || 1);
  const totalHeat = entries.reduce((s, e) => s + e.heat, 0);
  let roll = r() * totalHeat, culpritAt = 0;
  for (let i = 0; i < entries.length; i++) { roll -= entries[i].heat; if (roll <= 0) { culpritAt = i; break; } }
  const culprit = entries[culpritAt].idx, C = P[culprit];
  const cAccess = accessRoles(view, C);
  const tieW = (a, b) => { for (const e of view.web.adj.get(a) || []) if (e.to === b) return e.w; return 0; };
  const sched = new Map();                                          // idx → six watches (stable per orig identity)
  const schedOf = (i) => { let s = sched.get(i); if (!s) sched.set(i, s = scheduleFor(P[i], view.seed)); return s; };

  // 3. THE CRIME + THE CLUES — try the four waking watches until the clue list closes uniquely.
  for (let attempt = 0; attempt < 4; attempt++) {
    const tick = 1 + ((hash(caseSeed, 0x71c4, n) + attempt) % 4);
    const scene = schedOf(victim)[tick];
    const sceneName = pn(view, scene.place);

    // the suspect dossiers: claim (their scheduled place), witnesses there, independence.
    const suspects = entries.map((e) => {
      const S = P[e.idx], claim = schedOf(e.idx)[tick];
      let wit = 0, indep = 0;
      for (let j = 0; j < P.length; j++) {
        if (j === e.idx || j === victim) continue;
        if (schedOf(j)[tick].place !== claim.place) continue;
        wit++; if (tieW(e.idx, j) < INDEP_W) indep++;
      }
      const isC = e.idx === culprit;
      return {
        idx: e.idx, orig: S.orig, name: S.name, age: S.age, pronouns: S.pronouns, faction: S.faction || null,
        tribe: view.tribal.tribeOf[e.idx], tribeName: view.tribal.tribes[view.tribal.tribeOf[e.idx]].name,
        motives: e.motives, heat: e.heat, access: [...accessRoles(view, S)],
        claim: { place: claim.place, name: pn(view, claim.place), kind: claim.kind },
        witnesses: wit, independent: indep,
        corroborated: isC ? false : indep >= 1,                     // the culprit was NOT where they claim
        atScene: claim.place === scene.place,
      };
    });

    // the planted item: from the culprit's access set. Pacing wants it to keep suspects alive
    // (an item only the culprit could touch is a one-clue case) — but always maximizing keeps
    // picking the canteen ration (food access is near-universal), so a seeded draw picks among
    // every culprit-accessible item that keeps ≥2 on the board, for VARIETY. A culprit whose
    // hats touch none of the means roles (a pure scholar, say) falls back to the cord — the
    // weapon that narrows nothing, leaving the work to alibis and sightings.
    const usable = MEANS_ITEMS.filter((m) => cAccess.has(m.role));
    const keepOf = new Map(usable.map((m) => [m.role, suspects.filter((s) => s.access.includes(m.role)).length]));
    const cand = usable.filter((m) => keepOf.get(m.role) >= 2);
    const pool = cand.length ? cand : usable.length ? usable : [FALLBACK_MEANS];
    const item = pool[Math.floor(r() * pool.length)];

    // assemble clues in narrative order; each carries who it ELIMINATES (closure runs on these).
    const clues = [];
    const alive = new Set(suspects.map((s) => s.idx));
    const addClue = (kind, title, text, elim = []) => {
      const el = elim.filter((i) => alive.has(i) && i !== culprit);
      clues.push({ id: clues.length, kind, title, text, eliminates: el });
      for (const i of el) alive.delete(i);
    };
    addClue('body', `the body at ${sceneName}`,
      `${V.name} — found at the ${sceneName} during ${TICK_LABEL[tick]}. ${V.age}, ${V.kinship} of the ${V.surname} household, of ${view.tribal.tribes[view.tribal.tribeOf[victim]].name}. The neighbourhood has opinions about who wanted this.`);
    const topM = suspects[0].motives[0];
    addClue('rumor', 'what the benches say',
      `Loudest of the grievances: ${suspects[0].name} ${topM.tag === 'RIVAL' ? topM.text : `— ${topM.tag.toLowerCase()}, as everyone below a certain age already knows.`} Nobody is accusing. Everybody is implying.`);
    const noAccess = item.role ? suspects.filter((s) => !s.access.includes(item.role)) : [];
    addClue('means', `the coroner’s finding`,
      item.role
        ? `The instrument was ${item.item} — ${item.tell}. ${noAccess.map((s) => s.name).join(' and ') || 'Everyone on the board'} ${noAccess.length ? 'had no such access.' : 'could have laid hands on one.'}`
        : `The instrument was ${item.item}. It narrows nothing — ${item.tell}.`,
      noAccess.map((s) => s.idx));
    // the canvass — one alibi clue per suspect, in seeded order; only INDEPENDENT corroboration clears.
    const order = [...suspects].sort((a, b) => hash(caseSeed, 0xa11b, a.idx) - hash(caseSeed, 0xa11b, b.idx));
    for (const s of order) {
      if (!alive.has(s.idx) && s.idx !== culprit) continue;         // already off the board — skip the legwork
      if (s.idx === culprit) {
        addClue('alibi', `${s.name}’s account`, s.atScene
          ? `${s.name} was at the ${s.claim.name} — the scene itself — and does not deny it. "Half the district was through there."`
          : s.independent >= 1
            ? `${s.name} claims ${TICK_LABEL[tick]} at the ${s.claim.name} — but of ${s.witnesses} present, those with no stake in ${s.pronouns[1]} say ${s.pronouns[0]} slipped out and came back flushed.`
            : `${s.name} claims the ${s.claim.name}. The only souls who can swear to it are ${s.pronouns[1] === 'them' ? 'their' : s.pronouns[1] === 'her' ? 'her' : 'his'} own circle — worth exactly what kin’s word is worth.`);
      } else if (s.corroborated) {
        addClue('alibi', `${s.name}’s account`,
          `${s.name} was at the ${s.claim.name} all ${TICK_LABEL[tick]} — ${s.independent} of the ${s.witnesses} present owe ${s.pronouns[1]} nothing and swear to it. Off the board.`, [s.idx]);
      } else {
        addClue('alibi', `${s.name}’s account`,
          `${s.name} claims the ${s.claim.name}. ${s.witnesses ? `All ${s.witnesses} who agree are ${s.pronouns[1] === 'them' ? 'their' : s.pronouns[1] === 'her' ? 'her' : 'his'} own people — household and close ties. Unverifiable either way.` : 'No one at all can place ' + s.pronouns[1] + ' there. Unverifiable either way.'}`);
      }
    }
    // sightings — descriptors of the figure, planted only while they still eliminate someone.
    const descs = [
      { ok: (s) => band(s.age) === band(C.age), text: `A figure ${band(C.age) === 'young' ? 'quick and young' : band(C.age) === 'grey' ? 'grey and unhurried' : 'in their middle years'} was seen leaving the ${sceneName} as the watch turned.` },
      { ok: (s) => (s.faction || null) === (C.faction || null), text: C.faction ? `The figure wore ${C.faction} ward colours.` : `The figure wore no ward colours at all.` },
      { ok: (s) => workRole(P[s.idx]) === workRole(C), text: workRole(C) ? `The figure’s hands and garb were a ${workRole(C)} worker’s — no mistaking the trade.` : `The figure’s hands were soft — no trade at all.` },
    ];
    for (const d of descs) {
      if (alive.size <= 1) break;
      const elim = suspects.filter((s) => alive.has(s.idx) && s.idx !== culprit && !d.ok(s)).map((s) => s.idx);
      if (elim.length) addClue('sighting', 'a figure, half-seen', d.text, elim);
    }
    // trace discriminator — a token from a haunt of the culprit's that survivors don't share.
    if (alive.size > 1) {
      const cPlaces = new Set(C.hats.filter((h) => h.place !== C.home).map((h) => h.place));
      let bestPl = -1, bestElim = [];
      for (const pl of cPlaces) {
        const elim = suspects.filter((s) => alive.has(s.idx) && s.idx !== culprit && !P[s.idx].hats.some((h) => h.place === pl)).map((s) => s.idx);
        if (elim.length > bestElim.length || (elim.length === bestElim.length && pl < bestPl)) { bestPl = pl; bestElim = elim; }
      }
      if (bestElim.length) addClue('trace', 'dropped by the door',
        `Under the sill: a member’s token of the ${pn(view, bestPl)}. Whoever came and went belongs there.`, bestElim);
    }
    if (alive.size > 1) {                                           // household discriminator
      const elim = suspects.filter((s) => alive.has(s.idx) && s.idx !== culprit && P[s.idx].home !== C.home).map((s) => s.idx);
      if (elim.length) addClue('trace', 'a hair, a thread',
        `Caught on the latch: a thread from a ${C.surname} household coat.`, elim);
    }
    if (alive.size > 1) {
      // the second canvass — an INDEPENDENT passerby on an adjoining watch can place a shaky
      // claimant after all (grounded: their schedule really does pass the claimed place).
      for (const s of suspects) {
        if (!alive.has(s.idx) || s.idx === culprit) continue;
        let vouch = -1;
        for (let j = 0; j < P.length && vouch < 0; j++) {
          if (j === s.idx || j === victim || j === culprit || board.has(j)) continue;
          if (tieW(s.idx, j) >= INDEP_W) continue;
          for (const dt of [-1, 1]) {
            const t2 = tick + dt; if (t2 < 0 || t2 >= TICKS.length) continue;
            if (schedOf(j)[t2].place === s.claim.place) { vouch = j; break; }
          }
        }
        if (vouch >= 0) addClue('alibi', 'the second canvass',
          `${P[vouch].name}, passing the ${s.claim.name} on the adjoining watch, can place ${s.name} there after all. Off the board.`, [s.idx]);
        if (alive.size <= 1) break;
      }
    }
    if (alive.size > 1) {
      // the reluctant eyewitness — somebody's schedule really did brush the scene; they talk.
      let eye = -1;
      for (let j = 0; j < P.length && eye < 0; j++) {
        if (j === victim || j === culprit || board.has(j)) continue;
        for (const dt of [-1, 1]) {
          const t2 = tick + dt; if (t2 < 0 || t2 >= TICKS.length) continue;
          if (schedOf(j)[t2].place === scene.place) { eye = j; break; }
        }
      }
      if (eye >= 0) addClue('sighting', 'the reluctant eyewitness',
        `${P[eye].name} was near the ${sceneName} as the watch turned, and finally says it plain: the figure was ${C.name}.`,
        suspects.filter((s) => alive.has(s.idx) && s.idx !== culprit).map((s) => s.idx));
    }
    if (alive.size > 1) continue;                                   // this watch won't close — try another

    // 4. THE ORACLE — replay the closure cold and certify it converges on exactly the culprit.
    const check = new Set(suspects.map((s) => s.idx));
    let lastElimAt = 0;
    clues.forEach((c, ci) => { for (const i of c.eliminates) { check.delete(i); lastElimAt = ci; } });
    if (check.size !== 1 || !check.has(culprit)) continue;

    const cause = entries[culpritAt].motives[0];
    return {
      n, seed: caseSeed, tick, tickLabel: TICK_LABEL[tick],
      scene: { place: scene.place, name: sceneName },
      victim: {
        idx: victim, orig: V.orig, name: V.name, age: V.age, pronouns: V.pronouns, surname: V.surname,
        kinship: V.kinship, faction: V.faction || null, tribeName: view.tribal.tribes[view.tribal.tribeOf[victim]].name,
        hats: V.hats.map((h) => ({ kind: h.kind, place: h.place, name: pn(view, h.place) })),
      },
      suspects, clues,
      truth: { culprit, culpritOrig: C.orig, name: C.name, motive: cause, item: item.item },
      vitality: { v: view.vital.vitality, tier: view.vital.tier },
      survivors: P.length, solvable: true, lastElimAt,
    };
  }
  return null;                                                      // no watch closed for this victim (very rare)
}

// ── THE CHAIN — a casebook: each closed case buries its dead and the next reads the scar ─────
// nextCase is the incremental step (the page uses it live); caseChain replays a whole book.
export function nextCase(G, removed, n) {
  const view = buildView(G, removed);
  return { view, c: generateCase(view, hash(G.seed, 0xca5e, n) >>> 0, n) };
}

export function caseChain(G, { cases = 3 } = {}) {
  const removed = new Set();
  const out = [];
  for (let n = 0; n < cases; n++) {
    const { c } = nextCase(G, removed, n);
    if (!c) break;
    out.push(c);
    removed.add(c.victim.orig); removed.add(c.truth.culpritOrig);
  }
  return { cases: out, removed };
}

export default { TICKS, TICK_LABEL, scheduleFor, buildView, grievancesAgainst, generateCase, nextCase, caseChain };
